function setRunning(on) {
  running = on;
  $("btn-gen").disabled = on;
  $("gen-label").textContent = on ? "\\u751F\\u6210\\u4E2D..." : "\\u751F\\u6210";
  $("gen-spin").classList.toggle("hidden", !on);
}
function openCfg() {
  $("settings").classList.add("open");
  $("main-body").classList.add("hidden");
  $("set-ak").value = cfg.ak || ""; $("set-sk").value = cfg.sk || "";
  $("set-url").value = cfg.url || "";
  $("set-tid").value = cfg.tid || "";
  $("set-wid").value = cfg.wid || "";
  if ($("set-in-node"))   $("set-in-node").value   = cfg.inNode   || "";
  if ($("set-out-node"))  $("set-out-node").value  = cfg.outNode  || "";
  if ($("set-in-class"))  $("set-in-class").value  = cfg.inClass  || "";
  if ($("set-out-class")) $("set-out-class").value = cfg.outClass || "";
}
